# Generated by openai (gpt-5.4)
# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from typing import Dict, List, Optional
from collections import Counter, defaultdict
from threading import Lock
import base64
import io

import numpy as np
from PIL import Image
from sklearn.linear_model import SGDClassifier

app = FastAPI(title="Crowdsourced Data Labeling System")

class ImageItemRequest(BaseModel):
    image_id: str = Field(..., min_length=1)
    image_base64: str = Field(..., min_length=1)

class LabelSubmissionRequest(BaseModel):
    image_id: str = Field(..., min_length=1)
    annotator_id: str = Field(..., min_length=1)
    label: str = Field(..., min_length=1)

class TrainRequest(BaseModel):
    image_ids: Optional[List[str]] = None

class PredictionRequest(BaseModel):
    image_base64: str = Field(..., min_length=1)

class ImageStore:
    def __init__(self):
        self.images: Dict[str, bytes] = {}
        self.labels_by_image: Dict[str, Dict[str, str]] = defaultdict(dict)
        self.lock = Lock()

store = ImageStore()

class SimpleImageClassifier:
    def __init__(self):
        self.model = SGDClassifier(loss="log_loss", max_iter=1000, tol=1e-3, random_state=42)
        self.classes_: Optional[np.ndarray] = None
        self.is_trained = False
        self.image_size = (32, 32)

    def _decode_image(self, image_base64: str) -> Image.Image:
        try:
            raw = base64.b64decode(image_base64)
            img = Image.open(io.BytesIO(raw)).convert("RGB")
            return img
        except Exception:
            raise ValueError("Invalid image_base64")

    def _featurize_pil(self, img: Image.Image) -> np.ndarray:
        img = img.resize(self.image_size)
        arr = np.asarray(img, dtype=np.float32) / 255.0
        return arr.flatten()

    def featurize_base64(self, image_base64: str) -> np.ndarray:
        img = self._decode_image(image_base64)
        return self._featurize_pil(img)

    def featurize_bytes(self, raw: bytes) -> np.ndarray:
        try:
            img = Image.open(io.BytesIO(raw)).convert("RGB")
            return self._featurize_pil(img)
        except Exception:
            raise ValueError("Corrupt stored image data")

    def train(self, X: np.ndarray, y: np.ndarray):
        classes = np.unique(y)
        if len(classes) < 2:
            raise ValueError("Training requires at least 2 unique labels")
        self.model = SGDClassifier(loss="log_loss", max_iter=1000, tol=1e-3, random_state=42)
        self.model.fit(X, y)
        self.classes_ = classes
        self.is_trained = True

    def predict(self, x: np.ndarray) -> str:
        if not self.is_trained:
            raise ValueError("Model is not trained")
        pred = self.model.predict(x.reshape(1, -1))[0]
        return str(pred)

classifier = SimpleImageClassifier()

def decode_base64_to_bytes(image_base64: str) -> bytes:
    try:
        return base64.b64decode(image_base64)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image_base64")

def aggregate_majority_vote(labels_by_annotator: Dict[str, str]) -> Optional[str]:
    if not labels_by_annotator:
        return None
    counts = Counter(labels_by_annotator.values())
    max_count = max(counts.values())
    winners = sorted([label for label, count in counts.items() if count == max_count])
    return winners[0]

@app.post("/images")
def upload_image(req: ImageItemRequest):
    raw = decode_base64_to_bytes(req.image_base64)
    try:
        Image.open(io.BytesIO(raw)).convert("RGB")
    except Exception:
        raise HTTPException(status_code=400, detail="Uploaded content is not a valid image")
    with store.lock:
        store.images[req.image_id] = raw
    return {"status": "stored", "image_id": req.image_id}

@app.post("/labels")
def submit_label(req: LabelSubmissionRequest):
    with store.lock:
        if req.image_id not in store.images:
            raise HTTPException(status_code=404, detail="image_id not found")
        store.labels_by_image[req.image_id][req.annotator_id] = req.label
        aggregated = aggregate_majority_vote(store.labels_by_image[req.image_id])
        total_labels = len(store.labels_by_image[req.image_id])
    return {
        "status": "accepted",
        "image_id": req.image_id,
        "annotator_id": req.annotator_id,
        "current_aggregated_label": aggregated,
        "total_labels": total_labels,
    }

@app.get("/images/{image_id}/aggregate")
def get_aggregated_label(image_id: str):
    with store.lock:
        if image_id not in store.images:
            raise HTTPException(status_code=404, detail="image_id not found")
        labels = dict(store.labels_by_image.get(image_id, {}))
    aggregated = aggregate_majority_vote(labels)
    return {
        "image_id": image_id,
        "labels": labels,
        "aggregated_label": aggregated,
        "num_annotations": len(labels),
    }

@app.get("/dataset")
def get_dataset():
    with store.lock:
        image_ids = list(store.images.keys())
        result = []
        for image_id in image_ids:
            labels = dict(store.labels_by_image.get(image_id, {}))
            result.append({
                "image_id": image_id,
                "num_annotations": len(labels),
                "aggregated_label": aggregate_majority_vote(labels),
                "labels": labels,
            })
    return {"items": result, "count": len(result)}

@app.post("/train")
def train_model(req: TrainRequest):
    with store.lock:
        selected_ids = req.image_ids if req.image_ids is not None else list(store.images.keys())
        if not selected_ids:
            raise HTTPException(status_code=400, detail="No images available for training")

        X_list = []
        y_list = []
        skipped = []

        for image_id in selected_ids:
            if image_id not in store.images:
                skipped.append({"image_id": image_id, "reason": "not_found"})
                continue
            aggregated = aggregate_majority_vote(store.labels_by_image.get(image_id, {}))
            if aggregated is None:
                skipped.append({"image_id": image_id, "reason": "no_labels"})
                continue
            try:
                x = classifier.featurize_bytes(store.images[image_id])
            except ValueError:
                skipped.append({"image_id": image_id, "reason": "invalid_image"})
                continue
            X_list.append(x)
            y_list.append(aggregated)

    if not X_list:
        raise HTTPException(status_code=400, detail="No labeled images available for training")

    X = np.vstack(X_list)
    y = np.array(y_list)

    try:
        classifier.train(X, y)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))

    return {
        "status": "trained",
        "num_samples": int(len(y)),
        "classes": sorted(list(set(y_list))),
        "skipped": skipped,
        "validation": None,
    }

@app.post("/predict")
def predict(req: PredictionRequest):
    try:
        x = classifier.featurize_base64(req.image_base64)
        pred = classifier.predict(x)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))
    return {"predicted_label": pred}

@app.get("/health")
def health():
    return {
        "status": "ok",
        "num_images": len(store.images),
        "num_labeled_images": sum(1 for _, labels in store.labels_by_image.items() if labels),
        "model_trained": classifier.is_trained,
    }